import React, { useState } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import './Mentors.css';

const Mentors = () => {
  const [selectedField, setSelectedField] = useState('all');
  const { user } = useAuth();

  const mentorFields = [
    'all',
    'technology',
    'business',
    'design',
    'data-science',
    'marketing',
    'healthcare'
  ];

  const mentors = [
    {
      id: 1,
      name: 'Sarah Johnson',
      title: 'Senior Software Engineer at Google',
      field: 'technology',
      experience: '8+ years',
      specialization: ['Web Development', 'System Architecture', 'Cloud Computing'],
      availability: '2 spots available',
      rating: 4.9,
      sessions: 245,
      image: 'https://randomuser.me/api/portraits/women/32.jpg',
      bio: 'Passionate about helping newcomers break into tech. Specialized in full-stack development and career guidance.',
      linkedin: 'https://linkedin.com/in/sarahjohnson'
    },
    {
      id: 2,
      name: 'Michael Chen',
      title: 'Product Design Lead at Airbnb',
      field: 'design',
      experience: '6+ years',
      specialization: ['UI/UX Design', 'Design Systems', 'User Research'],
      availability: '1 spot available',
      rating: 4.8,
      sessions: 189,
      image: 'https://randomuser.me/api/portraits/men/52.jpg',
      bio: 'Helping designers build impactful careers. Expert in design thinking and portfolio building.',
      linkedin: 'https://linkedin.com/in/michaelchen'
    },
    {
      id: 3,
      name: 'Dr. Emily Rodriguez',
      title: 'Data Science Manager at Netflix',
      field: 'data-science',
      experience: '10+ years',
      specialization: ['Machine Learning', 'Big Data', 'Business Intelligence'],
      availability: '3 spots available',
      rating: 4.9,
      sessions: 312,
      image: 'https://randomuser.me/api/portraits/women/68.jpg',
      bio: 'Mentoring the next generation of data scientists. Focus on practical ML applications and career growth.',
      linkedin: 'https://linkedin.com/in/emilyrodriguez'
    },
    {
      id: 4,
      name: 'David Kim',
      title: 'Startup Founder & Angel Investor',
      field: 'business',
      experience: '12+ years',
      specialization: ['Entrepreneurship', 'Fundraising', 'Business Strategy'],
      availability: '2 spots available',
      rating: 4.7,
      sessions: 178,
      image: 'https://randomuser.me/api/portraits/men/67.jpg',
      bio: 'Helping entrepreneurs turn ideas into successful businesses. 3 successful exits.',
      linkedin: 'https://linkedin.com/in/davidkim'
    }
  ];

  const filteredMentors = selectedField === 'all' 
    ? mentors 
    : mentors.filter(mentor => mentor.field === selectedField);

  const connectWithMentor = (linkedinUrl) => {
    window.open(linkedinUrl, '_blank');
  };

  const requestMentorship = (mentorId) => {
    alert(`Mentorship request sent to mentor #${mentorId}! They will contact you soon.`);
    // In real app: make API call to send mentorship request
  };

  if (!user) {
    return (
      <div className="mentors-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to connect with mentors.</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="mentors-container">
      <div className="container">
        <div className="mentors-header">
          <h1>👥 Career Mentors</h1>
          <p>Connect with experienced professionals who can guide your career journey</p>
        </div>

        <div className="mentors-filters">
          <h3>Filter by Field:</h3>
          <div className="filter-buttons">
            {mentorFields.map(field => (
              <button
                key={field}
                className={`filter-btn ${selectedField === field ? 'active' : ''}`}
                onClick={() => setSelectedField(field)}
              >
                {field.charAt(0).toUpperCase() + field.slice(1).replace('-', ' ')}
              </button>
            ))}
          </div>
        </div>

        <div className="mentors-grid">
          {filteredMentors.map(mentor => (
            <div key={mentor.id} className="mentor-card">
              <div className="mentor-header">
                <img src={mentor.image} alt={mentor.name} className="mentor-avatar" />
                <div className="mentor-info">
                  <h3>{mentor.name}</h3>
                  <p className="mentor-title">{mentor.title}</p>
                  <div className="mentor-stats">
                    <span className="rating">⭐ {mentor.rating}</span>
                    <span className="sessions">👥 {mentor.sessions} sessions</span>
                  </div>
                </div>
              </div>

              <div className="mentor-details">
                <p className="mentor-bio">{mentor.bio}</p>
                
                <div className="mentor-specialization">
                  <strong>Specializes in:</strong>
                  <div className="specialization-tags">
                    {mentor.specialization.map((skill, index) => (
                      <span key={index} className="specialization-tag">{skill}</span>
                    ))}
                  </div>
                </div>

                <div className="mentor-meta">
                  <span className="experience">🎯 {mentor.experience} experience</span>
                  <span className="availability">{mentor.availability}</span>
                </div>
              </div>

              <div className="mentor-actions">
                <button 
                  onClick={() => connectWithMentor(mentor.linkedin)}
                  className="btn btn-secondary"
                >
                  View LinkedIn
                </button>
                <button 
                  onClick={() => requestMentorship(mentor.id)}
                  className="btn btn-primary"
                >
                  Request Mentorship
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Mentors;
